        isScrolled ? 'bg-brand-black/90 backdrop-blur-md py-4 border-b border-white/10' : 'bg-transparent py-6'
      }`}
    >
      <div className="container mx-auto px-6 flex justify-between items-center">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => scrollToSection('hero')}>
          <Scissors className="text-white w-6 h-6 rotate-90" />
          <span className="font-display font-bold text-2xl tracking-tighter text-white">
            AB <span className="text-gray-400">BARBER</span>
          </span>
        </div>

        {/* Desktop Menu */}
        <div className="hidden md:flex gap-8 items-center">
          {['Serviços', 'Marcação', 'Galeria', 'Localização'].map((item) => (
            <button
              key={item}
              onClick={() => scrollToSection(item)}
              className="text-sm font-medium text-gray-300 hover:text-white uppercase tracking-widest transition-colors"
            >
              {item}
            </button>
          ))}
          <button onClick={() => scrollToSection('localização')} className="bg-white text-black px-5 py-2 font-bold uppercase text-xs tracking-widest hover:bg-gray-200 transition-colors">
            Marcar
          </button>
        </div>

        {/* Mobile Toggle */}
        <button 
          className="md:hidden text-white"
          onClick={() => setIsMenuOpen(!isMenuOpen)}
        >
          {isMenuOpen ? <X /> : <Menu />}
        </button>
      </div>

      {/* Mobile Menu */}
      <div className={`md:hidden absolute top-full left-0 w-full bg-brand-black border-b border-white/10 transition-all duration-300 overflow-hidden ${isMenuOpen ? 'max-h-96 opacity-100' : 'max-h-0 opacity-0'}`}>
        <div className="flex flex-col p-6 gap-4">
          {['Serviços', 'Marcação', 'Galeria', 'Localização'].map((item) => (
            <button
              key={item}
              onClick={() => scrollToSection(item)}
              className="text-left text-lg font-display uppercase tracking-widest text-gray-300 hover:text-white"
            >
              {item}
            </button>
          ))}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState, useRef, useEffect } from 'react';
import { Send, Calendar, Clock, Terminal } from 'lucide-react';
import { ChatMessage } from '../types';
import ScrollReveal from './ScrollReveal';

const AIStyleConsultant: React.FC = () => {
  const [query, setQuery] = useState('');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'model', text: 'Bem-vindo ao Terminal AB Barber. O sistema de agendamento mais rápido de Caminha.' },
    { role: 'model', text: "Digite 'MARCAR' para acessar a agenda online instantaneamente." }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    const userText = query;
    setQuery('');
    setMessages(prev => [...prev, { role: 'user', text: userText }]);

    // Simula processamento do terminal
    setIsLoading(true);

    setTimeout(() => {
      if (userText.toLowerCase().includes('marcar') || userText.toLowerCase().includes('agendar')) {
         setMessages(prev => [...prev, { role: 'model', text: 'A iniciar protocolo de agendamento externo...' }]);
         setTimeout(() => {
             // Redirecionamento simulado
             window.open('#', '_blank'); // Aqui colocaria o link real da barbearia
             setMessages(prev => [...prev, { role: 'model', text: 'Janela de agendamento aberta com sucesso.' }]);
             setIsLoading(false);
         }, 1000);
      } else {
         setMessages(prev => [...prev, { role: 'model', text: "Comando não reconhecido. Por favor digite 'MARCAR' para iniciar." }]);
         setIsLoading(false);
      }
    }, 600);
  };

  return (
    <section id="marcacao" className="py-24 bg-brand-dark relative overflow-hidden">
      {/* Decorative Elements */}
      <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>

      <div className="container mx-auto px-6 grid md:grid-cols-2 gap-12 items-center">

        <ScrollReveal direction="right">
          <div>
            <div className="flex items-center gap-3 mb-4 text-white/80">
              <Calendar className="w-5 h-5" />
              <span className="uppercase tracking-widest text-sm font-bold">Booking System</span>
            </div>
            <h2 className="font-display text-4xl md:text-5xl font-bold text-white mb-6 uppercase leading-tight">
              Garanta o teu <br />
              <span className="text-gray-500">Horário</span>
            </h2>
            <p className="text-gray-400 mb-8 font-light text-lg">
              Sem chamadas, sem espera. Usa o nosso terminal direto para escolher o melhor slot para ti.
            </p>
            <ul className="space-y-4 text-gray-300 text-sm">
              <li className="flex items-center gap-3">
                <span className="w-1.5 h-1.5 bg-white rounded-full"></span>
                Agenda 24/7 Disponível
              </li>
              <li className="flex items-center gap-3">
                <span className="w-1.5 h-1.5 bg-white rounded-full"></span>
                Escolha o Barbeiro
              </li>
              <li className="flex items-center gap-3">
                <span className="w-1.5 h-1.5 bg-white rounded-full"></span>
                Confirmação Imediata
              </li>
            </ul>
          </div>
        </ScrollReveal>

        <ScrollReveal direction="left" delay={200}>
          <div className="bg-black border border-white/10 rounded-xl overflow-hidden shadow-2xl h-[500px] flex flex-col relative font-mono">
            <div className="p-4 border-b border-white/10 bg-brand-gray/50 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Terminal className="w-4 h-4 text-gray-400" />
                <span className="text-xs text-gray-400 uppercase">root@ab_barber:~/booking</span>
              </div>
              <div className="flex gap-1.5">
                <div className="w-2.5 h-2.5 rounded-full bg-red-500/50"></div>
                <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/50"></div>
                <div className="w-2.5 h-2.5 rounded-full bg-green-500/50"></div>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 scrollbar-hide bg-black/80 backdrop-blur-sm">
              {messages.map((msg, idx) => (
                <div key={idx} className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                  {msg.role === 'model' && (
                     <span className="text-[10px] text-green-500 mb-1 uppercase tracking-wider">system_response</span>
                  )}
                  {msg.role === 'user' && (
                     <span className="text-[10px] text-blue-500 mb-1 uppercase tracking-wider">user_input</span>
                  )}
                  <div className={`max-w-[90%] p-3 border-l-2 text-sm ${
                    msg.role === 'user' 
                      ? 'border-blue-500 bg-blue-500/10 text-blue-100' 
                      : 'border-green-500 bg-green-500/10 text-green-100'
                  }`}>
                    <span className="opacity-50 mr-2">{msg.role === 'model' ? '>' : '$'}</span>
                    {msg.text}
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="flex items-start">
                  <div className="max-w-[90%] p-3 border-l-2 border-green-500 bg-green-500/10 text-green-100 text-sm flex items-center gap-2">
                    <span className="opacity-50 mr-2">{'>'}</span>
                    <span className="animate-pulse">A processar solicitação...</span>
                  </div>
                </div>
              )}
              <div ref={messagesEndRef} />
            </div>

            <form onSubmit={handleSubmit} className="p-4 bg-brand-black border-t border-white/10 flex gap-2">
              <div className="flex-1 bg-brand-gray/30 border border-white/10 rounded-lg flex items-center px-4">
                <span className="text-green-500 mr-2">$</span>
                <input
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder="Digite 'MARCAR'..."
                  className="flex-1 bg-transparent text-white text-sm py-3 focus:outline-none placeholder-gray-600 font-mono"
                  autoComplete="off"
                />
              </div>
              <button 
                type="submit" 
                disabled={isLoading}
                className="bg-white text-black p-3 rounded-lg hover:bg-gray-200 transition-colors disabled:opacity-50"
              >
                <Send className="w-5 h-5" />
              </button>
            </form>
          </div>
        </ScrollReveal>

      </div>
    </section>
  );
};

export default AIStyleConsultant;
